                    "description": "Bloodline memberships at time of archival"
                }
            }
        },
        "LifecycleProfileSummary": {
            "type": "object",
            "additionalProperties": false,
            "description": "Lifecycle profile data returned by get and query endpoints",
            "required": [
                "characterId",
                "gameServiceId",
                "realmId",
                "speciesCode",
                "birthGameYear",
                "currentAge",
                "currentStage",
                "causeOfCreation",
                "childCount",
                "totalChildCount",
                "fertilityModifier",
                "healthModifier",
                "status"
            ],
            "properties": {
                "characterId": {
                    "type": "string",
                    "format": "uuid",
                    "description": "The character being tracked"
                },
                "gameServiceId": {
                    "type": "string",
                    "format": "uuid",
                    "description": "Game service scope"
                },
                "realmId": {
                    "type": "string",
                    "format": "uuid",
                    "description": "Realm for worldstate time queries"
                },
                "speciesCode": {
                    "type": "string",
                    "description": "Species determines stage thresholds and longevity",
                    "minLength": 1,
                    "maxLength": 100
                },
                "birthGameYear": {
                    "type": "integer",
                    "description": "Game year of birth (from worldstate)"
                },
                "birthSeason": {
                    "type": "string",
                    "nullable": true,
                    "description": "Season of birth (game-configurable from Worldstate calendar)",
                    "maxLength": 50
                },
                "currentAge": {
                    "type": "integer",
                    "description": "Current age in game years",
                    "minimum": 0
                },
                "currentStage": {
                    "type": "string",
                    "description": "Current lifecycle stage code (species-configurable)",
                    "minLength": 1,
                    "maxLength": 50
                },
                "causeOfCreation": {
                    "$ref": "#/$defs/CreationCause",
                    "description": "How this character was created"
                },
                "parentAId": {
                    "type": "string",
                    "format": "uuid",
                    "nullable": true,
                    "description": "First parent (null for seeded/spawned characters)"
                },
                "parentBId": {
                    "type": "string",
                    "format": "uuid",
                    "nullable": true,
                    "description": "Second parent (null for seeded/spawned characters)"
                },
                "householdOrgId": {
                    "type": "string",
                    "format": "uuid",
                    "nullable": true,
                    "description": "Organization ID of household"
                },
                "marriageContractIds": {
                    "type": "array",
                    "items": {
                        "type": "string",
                        "format": "uuid"
                    },
                    "description": "Active marriage contract IDs (empty if unmarried; array for polygamous cultures)"
                },
                "spouseCharacterIds": {
                    "type": "array",
                    "items": {
                        "type": "string",
                        "format": "uuid"
                    },
                    "description": "Current spouse character IDs (from Relationship, cached)"
                },
                "childCount": {
                    "type": "integer",
                    "description": "Living children count",
                    "minimum": 0
                },
                "totalChildCount": {
                    "type": "integer",
                    "description": "All children ever (including deceased)",
                    "minimum": 0
                },
                "fertilityModifier": {
                    "type": "number",
                    "format": "float",
                    "description": "Species + age + heritage fertility modifier",
                    "minimum": 0.0,
                    "maximum": 2.0
                },
                "healthModifier": {
                    "type": "number",
                    "format": "float",
                    "description": "Age-based health decline modifier",
                    "minimum": 0.0,
                    "maximum": 2.0
                },
                "naturalDeathYear": {
                    "type": "integer",
                    "nullable": true,
                    "description": "Projected natural death year (null if not yet calculated)"
                },
                "fulfillmentScore": {
                    "type": "number",
                    "format": "float",
                    "nullable": true,
                    "description": "Calculated at death from Disposition drives (0.0-1.0, null if alive)",
                    "minimum": 0.0,
                    "maximum": 1.0
                },
                "deathGameYear": {
                    "type": "integer",
                    "nullable": true,
                    "description": "Game year of death (null if alive)"
                },
                "deathCause": {
                    "type": "string",
                    "nullable": true,
                    "description": "Game-extensible death cause code (e.g., natural, combat, disease)",
                    "maxLength": 100
                },
                "afterlifePath": {
                    "type": "string",
                    "nullable": true,
                    "description": "Determined at death processing (game-configurable pathway code)",
                    "maxLength": 100
                },
                "status": {
                    "$ref": "#/$defs/LifecycleStatus",
                    "description": "Current lifecycle status"
                }
            }
        },
        "CreationCause": {
            "type": "string",
            "description": "How a character was created in the lifecycle system",
            "enum": [
                "Procreation",
                "Seeded",
                "Divine",
                "Spawned"
            ]
        },
        "LifecycleStatus": {
            "type": "string",
            "description": "Current lifecycle status of a character",
            "enum": [
                "Alive",
                "Dying",
                "Dead",
                "Archived"
            ]
        },
        "PhenotypeEntry": {
            "type": "object",
            "additionalProperties": false,
            "description": "Expressed phenotype value for a single genetic trait",
            "required": [
                "traitCode",
                "value",
                "expressionRule"
            ],
            "properties": {
                "traitCode": {
                    "type": "string",
                    "description": "Same code as genotype",
                    "minLength": 1,
                    "maxLength": 100
                },
                "value": {
                    "type": "number",
                    "format": "float",
                    "description": "The expressed phenotype value",
                    "minimum": 0.0,
                    "maximum": 1.0
                },
                "expressionRule": {
                    "$ref": "#/$defs/DominanceModel",
                    "description": "Which dominance model produced this value"
                }
            }
        },
        "DominanceModel": {
            "type": "string",
            "description": "Genetic dominance model determining how alleles combine to produce phenotype",
            "enum": [
                "DominantHigh",
                "DominantLow",
                "Blending",
                "Codominant",
                "Maternal",
                "Random"
            ]
        },
        "AptitudeEntry": {
            "type": "object",
            "additionalProperties": false,
            "description": "Derived skill aptitude from phenotype traits",
            "required": [
                "domain",
                "value"
            ],
            "properties": {
                "domain": {
                    "type": "string",
                    "description": "Skill domain code (e.g., smithing, enchanting)",
                    "minLength": 1,
                    "maxLength": 100
                },
                "value": {
                    "type": "number",
                    "format": "float",
                    "description": "Inherited aptitude value representing innate potential (0.0-1.0)",
                    "minimum": 0.0,
                    "maximum": 1.0
                }
            }
        },
        "BloodlineEntry": {
            "type": "object",
            "additionalProperties": false,
            "description": "Bloodline membership record for a character",
            "required": [
                "bloodlineId",
                "bloodlineCode",
                "originCharacterId",
                "originGameYear",
                "traitSignature",
                "generationFrom"
            ],
            "properties": {
                "bloodlineId": {
                    "type": "string",
                    "format": "uuid",
                    "description": "Bloodline identifier"
                },
                "bloodlineCode": {
                    "type": "string",
                    "description": "Human-readable bloodline code",
                    "minLength": 1,
                    "maxLength": 100
                },
                "originCharacterId": {
                    "type": "string",
                    "format": "uuid",
                    "description": "Character who founded or was first tracked member"
                },
                "originGameYear": {
                    "type": "integer",
                    "description": "When the bloodline was first identified"
                },
                "traitSignature": {
                    "type": "array",
                    "items": {
                        "type": "string"
                    },
                    "description": "Trait codes that characterize this bloodline"
                },
                "generationFrom": {
                    "type": "integer",
                    "description": "Generations from origin to this character",
                    "minimum": 0
                }
            }
        }
    }
}
""";

